// Validates that textureDimension is usable in a switch statement (constexpr-friendly).
static bool TestTextureDimensionSwitch()
{
    // Switch on a runtime textureDimension value from a generated entry
    AllSrvTextureDimensions inputs;
    int hitCount = 0;

    for (uint32_t i = 0; i < AllSrvTextureDimensions::NumResources; ++i)
    {
        switch (inputs.m_Resources[i].textureDimension)
        {
            case srrhi::TextureDimension::Texture1D:
            case srrhi::TextureDimension::Texture1DArray:
            case srrhi::TextureDimension::Texture2D:
            case srrhi::TextureDimension::Texture2DArray:
            case srrhi::TextureDimension::TextureCube:
            case srrhi::TextureDimension::TextureCubeArray:
            case srrhi::TextureDimension::Texture2DMS:
            case srrhi::TextureDimension::Texture2DMSArray:
            case srrhi::TextureDimension::Texture3D:
                ++hitCount;
                break;
            case srrhi::TextureDimension::None:
                // Should never reach here for SRV textures
                VALIDATE(false);
                break;
        }
    }

    VALIDATE(hitCount == 9);
    printf("  [PASS] textureDimension is usable in switch statements\n");
    return true;
}

