// =============================================================================
// MAIN
// =============================================================================

int main()
{
    int failures = 0;

    auto run = [&](const char* name, bool(*fn)()) {
        printf("Test: %s\n", name);
        try
        {
            if (!fn())
            {
                fprintf(stderr, "FAIL: %s returned false\n", name);
                ++failures;
            }
        }
        catch (const std::exception& ex)
        {
            fprintf(stderr, "FAIL: %s threw: %s\n", name, ex.what());
            ++failures;
        }
    };

    run("TextureDimension SRV kinds",                      TestSrvTextureDimensions);
    run("TextureDimension UAV kinds (== SRV counterpart)", TestUavTextureDimensions);
    run("Non-texture resources have TextureDimension::None", TestNonTextureDimensionIsNone);
    run("Mixed srinput TextureDimension per entry",         TestMixedTextureDimensions);
    run("SetterTestInputs TextureDimension (all 24)",       TestSetterTestInputsDimensions);
    run("textureDimension usable in switch",                TestTextureDimensionSwitch);

    if (failures == 0)
    {
        printf("\nAll TextureDimension tests PASSED.\n");
        return 0;
    }
    else
    {
        fprintf(stderr, "\n%d TextureDimension test(s) FAILED.\n", failures);
        return 1;
    }
}
